    # Demonstration
    system.add_student("101", "Alice", 20, "A")
    system.add_student("102", "Bob", 22, "B")

    system.view_students()

    system.remove_student("101")

    system.view_students()

import heapq
import datetime

class Task:
    """Represents a task with a priority and description."""
    def __init__(self, priority, description):
        self.priority = priority
        self.description = description
        self.created_at = datetime.datetime.now()

    def __lt__(self, other):
        # Heapq is a min-heap; lower integer value means higher priority
        return self.priority < other.priority

class TaskScheduler:
    """Manages tasks using a priority queue."""
    def __init__(self):
        self.task_queue = []

    def add_task(self, priority, description):
        """Adds a task to the scheduler."""
        task = Task(priority, description)
        heapq.heappush(self.task_queue, task)
        print(f"Task added: '{description}' with priority {priority}")

    def run_next_task(self):
        """Processes the highest priority task."""
        if self.task_queue:
            task = heapq.heappop(self.task_queue)
            print(f"Processing: '{task.description}' (Priority: {task.priority})")
        else:
            print("No tasks in queue.")

    def list_pending_tasks(self):
        """Displays all pending tasks sorted by priority."""
        print("\n--- Pending Tasks ---")
        if not self.task_queue:
            print("Queue is empty.")
        else:
            # Sorted to display without modifying the heap
            for task in sorted(self.task_queue):
                print(f"[{task.priority}] {task.description}")
        print("---------------------\n")


if __name__ == "__main__":
    scheduler = TaskScheduler()

    # Demonstration
    scheduler.add_task(3, "Send email")
    scheduler.add_task(1, "Fix critical bug")
    scheduler.add_task(2, "Update documentation")

    scheduler.list_pending_tasks()

    scheduler.run_next_task()

    scheduler.list_pending_tasks()

class WeatherDataProcessor:
    """Processes daily temperature readings to calculate statistics."""
    def __init__(self):
        self.daily_temps = []

    def add_reading(self, temperature):
        """Records a new temperature reading."""
        self.daily_temps.append(float(temperature))

    def get_statistics(self):
        """Calculates average, maximum, and minimum temperatures."""
        if not self.daily_temps:
            return None

        avg_temp = sum(self.daily_temps) / len(self.daily_temps)
        max_temp = max(self.daily_temps)
        min_temp = min(self.daily_temps)

        return {
            "average": avg_temp,
            "max": max_temp,
            "min": min_temp,
            "count": len(self.daily_temps)
        }

    def display_report(self):
        """Prints the processed weather data report."""
        stats = self.get_statistics()
        print("\n--- Weather Data Report ---")
        if not stats:
            print("No data available to process.")
        else:
            print(f"Readings processed: {stats['count']}")
            print(f"Average Temp: {stats['average']:.2f}°C")
            print(f"Maximum Temp: {stats['max']:.2f}°C")
            print(f"Minimum Temp: {stats['min']:.2f}°C")
        print("---------------------------\n")


if __name__ == "__main__":
    processor = WeatherDataProcessor()

    # Demonstration
    readings = [22.5, 24.0, 19.5, 21.0, 26.5]
    for temp in readings:
        processor.add_reading(temp)

    processor.display_report()

