def minimum_coins(amount, coins):
    dp = [float("inf")] * (amount + 1)
    dp[0] = 0

    for value in range(1, amount + 1):
        for coin in coins:
            if coin <= value:
                dp[value] = min(dp[value], dp[value - coin] + 1)

    return dp[amount]

coins = [1, 5, 10, 25]
amount = 37

print("Minimum coins:", minimum_coins(amount, coins))

