import os


def search_files(root_directory, keyword):
    matches = []

    for current_root, _, files in os.walk(root_directory):
        for filename in files:
            if keyword.lower() in filename.lower():
                matches.append(os.path.join(current_root, filename))

    return matches


def main():
    directory = input("Directory to search: ").strip()
    keyword = input("Filename keyword: ").strip()

    if not os.path.isdir(directory):
        print("Invalid directory.")
        return

    results = search_files(directory, keyword)

    if not results:
        print("No matching files found.")
        return

    print("\nMatching files:")
    for path in results:
        print(path)


if __name__ == "__main__":
    main()

