import json


def display_data(data, indent=0):
    prefix = " " * indent

    if isinstance(data, dict):
        for key, value in data.items():
            print(f"{prefix}{key}:")
            display_data(value, indent + 4)

    elif isinstance(data, list):
        for index, item in enumerate(data, start=1):
            print(f"{prefix}[{index}]")
            display_data(item, indent + 4)

    else:
        print(f"{prefix}{data}")


def load_json_file(path):
    try:
        with open(path, "r", encoding="utf-8") as file:
            return json.load(file)

    except FileNotFoundError:
        print("File not found.")

    except json.JSONDecodeError as error:
        print(f"Invalid JSON: {error}")

    return None


def main():
    filename = input("JSON file path: ").strip()
    data = load_json_file(filename)

    if data is not None:
        print("\nParsed Data")
        print("-" * 30)
        display_data(data)


if __name__ == "__main__":
    main()

from dataclasses import dataclass


@dataclass
class Item:
    name: str
    weight: int
    value: int


def solve_knapsack(items, capacity):
    item_count = len(items)
    dp = [[0] * (capacity + 1) for _ in range(item_count + 1)]

    for i in range(1, item_count + 1):
        item = items[i - 1]

        for current_capacity in range(capacity + 1):
            if item.weight <= current_capacity:
                include = item.value + dp[i - 1][current_capacity - item.weight]
                exclude = dp[i - 1][current_capacity]
                dp[i][current_capacity] = max(include, exclude)
            else:
                dp[i][current_capacity] = dp[i - 1][current_capacity]

    selected_items = []
    remaining_capacity = capacity

    for i in range(item_count, 0, -1):
        if dp[i][remaining_capacity] != dp[i - 1][remaining_capacity]:
            selected_items.append(items[i - 1])
            remaining_capacity -= items[i - 1].weight

    return dp[item_count][capacity], list(reversed(selected_items))


def main():
    items = [
        Item("Laptop", 3, 2000),
        Item("Camera", 1, 1500),
        Item("Headphones", 1, 800),
        Item("Tablet", 2, 1200),
    ]

    capacity = 4

    best_value, chosen_items = solve_knapsack(items, capacity)

    print("Knapsack Capacity:", capacity)
    print("Maximum Value:", best_value)
    print("\nSelected Items:")

    for item in chosen_items:
        print(f"- {item.name} (Weight={item.weight}, Value={item.value})")


if __name__ == "__main__":
    main()

class Library:
    def __init__(self):
        self.books = {}

    def add_book(self, title):
