from collections import Counter


def analyze_log_file(log_path):
    counts = Counter({"INFO": 0, "WARNING": 0, "ERROR": 0})

    try:
        with open(log_path, "r", encoding="utf-8") as log_file:
            for line in log_file:
                for level in counts:
                    if level in line:
                        counts[level] += 1

    except FileNotFoundError:
        print("Log file not found.")
        return None

    return counts


def print_report(counts):
    print("\nLog Summary Report")
    print("-" * 25)

    for level, total in counts.items():
        print(f"{level:<10}: {total}")

    print("-" * 25)
    print("Total Entries:", sum(counts.values()))


def main():
    path = input("Log file path: ").strip()

    summary = analyze_log_file(path)

    if summary:
        print_report(summary)


if __name__ == "__main__":
    main()

def longest_common_subsequence(first, second):
    rows = len(first) + 1
    cols = len(second) + 1

    dp = [[0] * cols for _ in range(rows)]

    for i in range(1, rows):
        for j in range(1, cols):
            if first[i - 1] == second[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    sequence = []
    i = len(first)
    j = len(second)

    while i > 0 and j > 0:
        if first[i - 1] == second[j - 1]:
            sequence.append(first[i - 1])
            i -= 1
            j -= 1
        elif dp[i - 1][j] > dp[i][j - 1]:
            i -= 1
        else:
            j -= 1

    return "".join(reversed(sequence))


def main():
    string_a = "AGGTAB"
    string_b = "GXTXAYB"

    result = longest_common_subsequence(string_a, string_b)

    print("String A:", string_a)
    print("String B:", string_b)
    print("LCS:", result)
    print("Length:", len(result))


if __name__ == "__main__":
    main()

class ParkingLot:
    def __init__(self, total_spaces):
        self.total_spaces = total_spaces
        self.occupied_spaces = {}

    def park_vehicle(self, plate_number):
        if len(self.occupied_spaces) >= self.total_spaces:
            print("Parking lot is full.")
            return

        if plate_number in self.occupied_spaces.values():
            print("Vehicle already parked.")
            return

        for space in range(1, self.total_spaces + 1):
            if space not in self.occupied_spaces:
                self.occupied_spaces[space] = plate_number
                print(f"Vehicle parked at space {space}.")
                return

    def remove_vehicle(self, plate_number):
        for space, plate in list(self.occupied_spaces.items()):
            if plate == plate_number:
                del self.occupied_spaces[space]
                print("Vehicle removed.")
                return

        print("Vehicle not found.")

    def display_occupied_spaces(self):
        if not self.occupied_spaces:
            print("No occupied spaces.")
            return

        print("\nOccupied Spaces")
        print("-" * 25)

        for space in sorted(self.occupied_spaces):
            print(f"Space {space}: {self.occupied_spaces[space]}")


def main():
    parking_lot = ParkingLot(10)

    while True:
        print("\n1. Park Vehicle")
        print("2. Remove Vehicle")
        print("3. Display Occupied Spaces")
        print("4. Exit")

        choice = input("Choice: ")

        if choice == "1":
            parking_lot.park_vehicle(input("Plate number: ").strip())

        elif choice == "2":
            parking_lot.remove_vehicle(input("Plate number: ").strip())

        elif choice == "3":
            parking_lot.display_occupied_spaces()

        elif choice == "4":
            break

        else:
            print("Invalid option.")


